					call_to_destroy = 0;
					AST_LIST_LOCK(&frame_queue);
					AST_LIST_TRAVERSE(&frame_queue, cur, list) {
						/* If it's our call, and our timestamp, mark -1 retries */
						if ((fr->callno == cur->callno) && (x == cur->oseqno)) {
							cur->retries = -1;
